/*@ Extern Coq (string_to_lower_ascii_spec : list Z -> list Z) */
/*@ Import Coq Require Import string_to_lower_ascii */

void string_to_lower_ascii(char *s)
/*@ With l n
    Require
      0 <= n && n < INT_MAX &&
      Zlength(l) == n &&
      (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure
      CharArray::full(s, n + 1, app(string_to_lower_ascii_spec(l), cons(0, nil)))
*/
{
    int i = 0;

    while (1) {
        if (s[i] == 0) {
            break;
        }
        if (65 <= s[i] && s[i] <= 90) {
            s[i] = s[i] - 65 + 97;
        }
        i++;
    }
}
Require Import ZArith.
Require Import Coq.Lists.List.

Open Scope Z_scope.

Definition lower_ascii_char (x : Z) : Z :=
  if Z_le_dec 65 x then
    if Z_le_dec x 90 then x - 65 + 97 else x
  else x.

Fixpoint string_to_lower_ascii_spec (l : list Z) : list Z :=
  match l with
  | nil => nil
  | x :: xs => lower_ascii_char x :: string_to_lower_ascii_spec xs
  end.

