void string_replace_char(char *s, char old_c, char new_c)
/*@ With l n
    Require
      0 <= n && n < INT_MAX &&
      Zlength(l) == n &&
      (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure
      CharArray::full(s, n + 1, app(string_replace_char_spec(l, old_c, new_c), cons(0, nil)))
*/
{
    int i = 0;

    while (1) {
        if (s[i] == 0) {
            break;
        }
        if (s[i] == old_c) {
            s[i] = new_c;
        }
        i++;
    }
}
Require Import ZArith.
Require Import Coq.Lists.List.

Open Scope Z_scope.

Definition replace_char (x old_c new_c : Z) : Z :=
  if Z.eq_dec x old_c then new_c else x.

Fixpoint string_replace_char_spec (l : list Z) (old_c new_c : Z) : list Z :=
  match l with
  | nil => nil
  | x :: xs => replace_char x old_c new_c :: string_replace_char_spec xs old_c new_c
  end.

