int remove_duplicates_sorted(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      n <= INT_MAX &&
      Zlength(l) == n &&
      (forall (i: Z), (0 <= i && i + 1 < n) => l[i] <= l[i + 1]) &&
      IntArray::full(a, n, l)
    Ensure
      exists lr t,
        __return == Zlength(remove_duplicates_sorted_spec(l)) &&
        0 <= __return && __return <= n &&
        Zlength(lr) == n &&
        lr == app(remove_duplicates_sorted_spec(l), t) &&
        IntArray::full(a, n, lr)
*/
{
    int i;
    int j;

    if (n == 0) {
        return 0;
